const resp = $.steps.scrapeUrl.response || {};
const data = resp.data || {};
const md = data.markdown || '';
const url = $.input.url;
const schema = $.input.schema;

const prompt = `You are a web scraping data extraction specialist. Extract structured data from the following scraped webpage content according to the user's schema definition.

SOURCE URL: ${url}

USER-DEFINED SCHEMA:
${schema}

SCRAPED CONTENT:
${md.slice(0, 8000)}

INSTRUCTIONS:
- Extract ALL items matching the user's schema from the page content
- Follow the schema fields exactly as specified
- If a field cannot be found, use null
- Normalize data types (numbers as numbers, etc.)
- Sort by the most relevant field if applicable

Return ONLY valid JSON:
{
  "pageTitle": "<title of the page>",
  "sourceUrl": "${url}",
  "schemaUsed": "${schema.slice(0, 100)}",
  "totalItems": 0,
  "items": [
    { /* fields per schema */ }
  ],
  "summary": "<one-line summary of extraction>"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { items: [], totalItems: 0, summary: raw, pageTitle: 'Scraped Data', sourceUrl: $.input.url }; }

const ai = $.steps.parseAI.output || {};
const items = ai.items || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Structured Data Extraction' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Source:* <' + (ai.sourceUrl || $.input.url) + '|' + (ai.pageTitle || 'Page') + '>\n*Schema:* ' + $.input.schema.slice(0, 200) + '\n*Items found:* ' + (ai.totalItems || items.length) } });
blocks.push({ type: 'divider' });

const maxItems = Math.min(items.length, 10);
for (let i = 0; i < maxItems; i++) {
  const item = items[i];
  const keys = Object.keys(item);
  let itemText = '*' + (i+1) + '.* ';
  keys.forEach((k, ki) => {
    const v = item[k] !== null && item[k] !== undefined ? String(item[k]) : 'N/A';
    itemText += '*' + k + ':* ' + v.slice(0, 150);
    if (ki < keys.length - 1) itemText += ' | ';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: itemText.slice(0, 1900) } });
}

if (items.length > 10) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_...and ' + (items.length - 10) + ' more items_' } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':spider_web: ' + (ai.summary || 'Data extracted successfully') }] });

const fallback = 'Extracted ' + items.length + ' items from ' + $.input.url;
return { blocks, fallback };
